{
  "expressions": [
    {
      "id": "parabola",
      "latex": "y=x^2",
      "color": "#c74440",
      "label": "x^2",
      "showLabel": true
    },
    {
      "id": "m",
      "latex": "m=0.3",
      "sliderBounds": { "min": -2, "max": 2, "step": 0.1 }
    },
    {
      "id": "n",
      "latex": "n=1.5",
      "sliderBounds": { "min": -3, "max": 3, "step": 0.1 }
    },
    {
      "id": "line",
      "latex": "y=m x + n",
      "color": "#000000",
      "label": "mx+n",
      "showLabel": true
    },
    {
      "id": "x0",
      "latex": "x_0=\\frac{m-\\sqrt{m^2+4n}}{2}",
      "hidden": true
    },
    {
      "id": "x1",
      "latex": "x_1=\\frac{m+\\sqrt{m^2+4n}}{2}",
      "hidden": true
    },
    {
      "id": "p0",
      "latex": "(x_0, x_0^2)",
      "color": "#2d70b3",
      "showLabel": true,
      "label": "x_0"
    },
    {
      "id": "p1",
      "latex": "(x_1, x_1^2)",
      "color": "#2d70b3",
      "showLabel": true,
      "label": "x_1"
    }
  ],
  "options": { "expressions": true, "settingsMenu": false, "keypad": false, "zoomButtons": false }
}
